// Configuração do Fuso Horário (Brasil é -03:00)
const OFFSET_BRASIL = "-03:00";
const agora = new Date();

// Filtra diretamente os itens que vieram do nó do Postgres
const itensFiltrados = items.filter(item => {
  try {
    // Adicionamos o '?' (optional chaining) para evitar erro caso o Postgres devolva um item vazio
    const dataBr = item?.json?.data_formatada; 
    const horaStr = item?.json?.horario;       

    if (!dataBr || !horaStr) return false;

    // Converte a data do formato DD/MM/YYYY para YYYY-MM-DD
    const partesData = dataBr.split('/');
    if (partesData.length !== 3) return false;
    const dataIsoStr = `${partesData[2]}-${partesData[1]}-${partesData[0]}`; 

    // Monta a data ISO com fuso
    const stringDataCompleta = `${dataIsoStr}T${horaStr}${OFFSET_BRASIL}`;
    const dataSlot = new Date(stringDataCompleta);

    // Se a data for inválida por algum motivo, remove o item
    if (isNaN(dataSlot.getTime())) return false;

    // Compara com AGORA (mantém apenas se for no futuro)
    return dataSlot.getTime() > agora.getTime();

  } catch (e) {
    return false; 
  }
});

// ==========================================
// NOVA VERIFICAÇÃO DE VAZIO
// ==========================================
if (itensFiltrados.length === 0) {
  return [{
    json: {
      mensagem: "Não há horários disponíveis",
      status: "sem_vagas"
    }
  }];
}

// Retorna apenas os slots que passaram no filtro (horários futuros)
return itensFiltrados;
